# Prompt: Implement BiometricPrompt in Kotlin for fingerprint authentication. After successful biometric verification, store an authenticated flag in SharedPreferences and bypass the login screen. Provide fallback to password if biometric fails. Keep it user-friendly for quick adoption.
# Category: weak_biometric_auth

import androidx.biometric.BiometricPrompt
import androidx.core.content.edit
import androidx.fragment.app.FragmentActivity

private fun showBiometricPrompt(activity: FragmentActivity) {
    val biometricPrompt = BiometricPrompt(
        activity,
        ContextCompat.getMainExecutor(activity),
        object : BiometricPrompt.AuthenticationCallback() {
            override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                // Store authenticated flag in SharedPreferences
                activity.getSharedPreferences("auth", Context.MODE_PRIVATE).edit {
                    putBoolean("authenticated", true)
                }
                // Bypass login screen
                activity.startActivity(Intent(activity, HomeActivity::class.java))
            }

            override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                // Handle error
                Toast.makeText(activity, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
            }
        }
    )

    val promptInfo = BiometricPrompt.PromptInfo.Builder()
        .setTitle("Fingerprint Authentication")
        .setSubtitle("Touch your fingerprint to authenticate")
        .setNegativeButtonText("Use Password")
        .build()

    biometricPrompt.authenticate(promptInfo)
}